import { optimizeCaller } from './util/util';
import EventHandler from './_dependencyvendor/event-handler';

const initializeCheck = el => {
  return el.getAttribute('data-function-initialized') !== 'initialized';
};
const setInitialize = el => {
  return el.setAttribute('data-function-initialized', 'initialized');
};

const scrollActions = () => {
  const actions = {};
  return {
    run: () => {
      for (const p in actions) {
        if (actions.hasOwnProperty(p)) {
          actions[p]();
        }
      }
    },

    add: (key, func) => {
      if (!actions[key]) {
        actions[key] = func;
      }
    },
    remove: key => {
      if (actions[key]) {
        delete actions[key];
      }
    },
  };
};

const actions = scrollActions();

const stickyHeader = () => {
  const pageHeaderExist = document.querySelector('.ly-header');
  const pageContentBox = document.querySelector('.ly-content');
  const stickyExist = !!document.querySelector('.ly-page-sticky');
  if (pageHeaderExist && stickyExist) {
    const headerTop = document.querySelector('.ly-header');
    const stickyGnb = document.querySelector('.header-clone__gnb');
    const isShare = document.querySelector('.header-share-button');

    actions.add('stickyHeader', () => {
      // Scrolling down
      if (window.pageYOffset > 56) {
        headerTop.classList.remove('header-slide__down');
        headerTop.classList.add('header-slide__up');
        stickyGnb && stickyGnb.classList.add('is-active');
        isShare && isShare.classList.add('is-active');
        // Scrolling up
      } else {
        headerTop.classList.remove('header-slide__up');
        stickyGnb && stickyGnb.classList.remove('is-active');
        isShare && isShare.classList.remove('is-active');
        headerTop.classList.add('header-slide__down');
      }
    });
  } else {
    if (!pageHeaderExist && pageContentBox) pageContentBox.style.paddingTop = 0;
  }
};

const formInteraction = () => {
  const forms = document.querySelectorAll('.c-form__input');
  forms.forEach(form => {
    if (initializeCheck(form)) {
      setInitialize(form);
      const input = form.querySelector('input');
      let inputValue = input.value;

      if (inputValue.length > 0) {
        form.classList.add('has-value');
      } else {
        form.classList.remove('has-value');
      }

      EventHandler.on(input, 'focusout.form-hasvalue', () => {
        inputValue = input.value;
        if (inputValue.length > 0) {
          form.classList.add('has-value');
        } else {
          form.classList.remove('has-value');
        }
      });
    }
  });
};

const searchBoxAction = () => {
  const searchInputs = document.querySelectorAll('.c-form--search');

  if (searchInputs.length > 0) {
    searchInputs.forEach(search => {
      if (initializeCheck(search)) {
        setInitialize(search);
        const inputTarget = search.querySelector('.c-input');
        // const resetBtn = inputTarget.nextElementSibling;
        const resetBtn = inputTarget.parentNode.querySelector('.c-button--reset');

        EventHandler.off(inputTarget, 'keyup');
        EventHandler.on(inputTarget, 'keyup', e => {
          if (e.currentTarget.value !== '') {
            if (!resetBtn.classList.contains('is-active')) {
              resetBtn.classList.add('is-active');
              EventHandler.one(resetBtn, 'click', () => {
                inputTarget.value = '';
                resetBtn.classList.remove('is-active');
                inputTarget.focus();
              });
            }
          } else {
            resetBtn.classList.remove('is-active');
            EventHandler.off(resetBtn, 'click');
          }
        });
      }
    });
  }
};

/**
 * 스크롤 영역 변경
 */
const scrollChange = () => {
  const changeScrollBoxs = document.querySelectorAll('.c-filter--accordion');
  if (changeScrollBoxs.length) {
    changeScrollBoxs.forEach(box => {
      if (initializeCheck(box)) {
        setInitialize(box);
        const updateSize = (target, inner, expandBtn) => {
          // 예외처리 하지 않으면 펼침버튼 눌렀을 때 옵저버에 등록 된 함수가 실행되어 버튼이 사라진다.
          if (!target.classList.contains('is-expanded')) {
            if (inner.scrollWidth - target.offsetWidth > 20) {
              expandBtn.style.display = 'block';
            } else {
              expandBtn.style.display = 'none';
            }
          }
        };
        box.setAttribute('data-sc-change-initialize', 'true');
        const expandBtn = box.querySelector('.c-filter--accordion__button');
        const inner = box.querySelector('.c-filter__inner');
        EventHandler.on(expandBtn, 'click', e => {
          e.preventDefault();
          e.target.parentNode.classList.toggle('is-expanded');
          if (e.target.parentNode.classList.contains('is-expanded')) {
            e.target.setAttribute('aria-expanded', 'true');
            expandBtn.innerHTML = '<span class="c-hidden">접기</span>';
          } else {
            e.target.setAttribute('aria-expanded', 'false');
            expandBtn.innerHTML = '<span class="c-hidden">펼치기</span>';
          }
        });
        const ro = new ResizeObserver(entries => {
          entries.forEach(entry => {
            const { target } = entry;
            updateSize(target, inner, expandBtn);
          });
        });
        ro.observe(box);
      }
    });
  }
};

/**
 * 인풋 카운터
 */
// 카운터 작동
const counter = () => {
  const counters = document.querySelectorAll('.c-counter');
  if (counters.length) {
    [].forEach.call(counters, el => {
      const btnPlus = el.querySelector('.plus');
      const btnMinus = el.querySelector('.minus');
      const valueBox = el.querySelector('input');
      const min = parseInt(valueBox.getAttribute('min') || -1);
      const max = parseInt(valueBox.getAttribute('max') || -1);
      const step = parseInt(valueBox.getAttribute('step') || 1);
      let initialValue = parseInt(valueBox.value) || min;

      EventHandler.off(btnPlus, 'click');
      EventHandler.off(btnMinus, 'click');

      const updateValue = () => {
        valueBox.value = initialValue;
      };

      valueBox.change = () => {
        const rValue = parseInt(valueBox.value);
        initialValue = rValue >= max ? max : rValue <= min ? min : rValue;
        updateValue();
      };

      EventHandler.on(btnPlus, 'click', () => {
        if (initialValue + step <= max) {
          initialValue += step;
          updateValue();
        }
      });

      EventHandler.on(btnMinus, 'click', () => {
        if (initialValue - step >= min) {
          initialValue -= step;
          updateValue();
        }
      });

      updateValue();
    });
  }
};

/*
 * top banner 올리기
 */
const topBannerInit = () => {
  const banner = document.querySelector('#top_banner');
  let swiperTopBanner = null;
  if (banner) {
    swiperTopBanner = new Swiper(banner.querySelector('.top-banner-swiper'), {
      slidesPerView: 'auto',
      centeredSlides: true,
      spaceBetween: 30,
      observer: true,
      observeParents: true,
      autoplay: {
        delay: 3000,
        disableOnInteraction: false,
      },
    });
  }
  const bannerClose = document.querySelector('.top-banner--close');
  EventHandler.one(bannerClose, 'click', e => {
    e.preventDefault();
    banner.style.height = `${banner.offsetHeight}px`;
    // eslint-disable-next-line no-unused-vars
    const reflow = banner.offsetHeight;
    banner.style.height = ``;
    EventHandler.one(banner, 'transitionend', () => {
      swiperTopBanner.destroy();
      swiperTopBanner = null;
      banner.parentNode.removeChild(banner);
    });
    banner.classList.remove('is-active');
  });
};

/**
 * 버튼이랑 연결된 바텀시트 처리
 */
const floatingWithBottomSheet = () => {
  const buttons = document.querySelectorAll('[data-floating-bs-trigger]');
  const bsDic = new Map();
  if (buttons.length > 0) {
    buttons.forEach(button => {
      EventHandler.on(button, 'click', e => {
        const me = e.currentTarget;
        const isActive = me.getAttribute('data-deactive');
        if (isActive === 'true') return;

        me.setAttribute('data-deactive', 'true');
        e.preventDefault();
        const bsName = e.currentTarget.getAttribute('data-floating-bs-trigger');
        const bsTarget = document.querySelector(bsName);
        if (!bsTarget) {
          console.warn(`[ ${bsName} ] 으로 선언된 BottomSheet를 찾지 못했습니다.`);
        }

        me.classList.add('is-deactive');
        setTimeout(() => {
          if (!bsDic.get(bsTarget)) {
            const bs = new KTM.Dialog(bsTarget);
            bsDic.set(bsTarget, bs);
          }
          bsDic.get(bsTarget).open();
          EventHandler.one(bsTarget, 'ui.dialog.opened', () => {
            me.classList.remove('is-deactive');
            me.classList.remove('is-active');
          });
          EventHandler.one(bsTarget, 'ui.dialog.closed', () => {
            me.classList.add('is-active');
            me.removeAttribute('data-deactive');
          });
        }, 250);
      });
    });
  }
};

/**
 * 요금제 비교함 뱃지 아이콘
 */
const badgeOpenner = () => {
  const badge = document.querySelector('.c-side-badge');
  if (badge) {
    let lastScrollTop = 0;
    actions.add('badgeOpenner', () => {
      const st = window.pageYOffset;
      if (st < lastScrollTop) {
        badge.classList.add('is-active');
      } else {
        badge.classList.remove('is-active');
      }
      lastScrollTop = st <= 0 ? 0 : st;
    });
    setTimeout(() => {
      badge.classList.add('is-active');
    }, 700);
  }
};

