/**
 * 전체메뉴
 */
const allMenu = () => {
  const allMenuContainer = document.querySelector('.nav-wrap');
  const navDim = document.querySelector('.nav-dim');
  const headerOpenner = document.querySelector('.ly-header__gnb');
  const headerOpenner2 = document.querySelector('.header-clone__gnb');

  const allMenuEl = document.querySelector('.nav-wrap__menu-sub.c-accordion');
  const allMenu = window.KTM.Accordion.getInstance(allMenuEl);

  if (allMenu) {
    const menuDepth = document.querySelectorAll('.depth1 a');
    const subDepth = document.querySelectorAll('.depth2');
    const allMenuCloseButoton = document.querySelector('.nav-wrap__link--close');
    let saveBodyScrollPos = 0;

    const openMenu = e => {
      e.preventDefault();
      allMenuContainer.style.display = 'block';
      navDim.style.display = 'block';
      // eslint-disable-next-line no-unused-vars
      const reflow = navDim.offsetHeight;
      allMenuContainer.classList.add('is-active');
      navDim.classList.add('is-active');
      saveBodyScrollPos = window.scrollY;
      document.body.style.overflow = 'hidden';
      activeCurrentPage();
    };

    const closeMenu = e => {
      e.preventDefault();
      if (allMenuContainer.classList.contains('is-active')) {
        allMenuContainer.classList.remove('is-active');
        navDim.classList.remove('is-active');
        document.body.style.overflow = 'auto';
        window.scrollY = saveBodyScrollPos;
        EventHandler.one(navDim, 'transitionend', () => {
          navDim.style.display = 'none';
          allMenuContainer.style.display = 'none';
          allMenu.closeAll();
        });
      }
    };

    const activeMenu = el => {
      // 서브메뉴 변경 시 아코디언 모두 닫기
      allMenu.closeAll();
      menuDepth.forEach(el => el.classList.remove('is-active'));
      el.classList.add('is-active');
    };

    const show = el => {
      el.style.display = 'block';
    };

    const hide = () => {
      subDepth.forEach(el => (el.style.display = 'none'));
    };

    const activeCurrentPage = () => {
      const activeMainDepth = id => {
        const mainMenu = document.querySelector(`a[href="#${id}"]`);
        if (mainMenu) {
          mainMenu.click();
        }
      };
      const wrapper = document.querySelector('.nav-wrap__menu');
      const codeInput = document.querySelector('#gnbMCode');
      if (!codeInput) return;
      const curentPageCode = codeInput.getAttribute('value');
      if (!curentPageCode) return;

      const pageCodes = wrapper.querySelectorAll('[data-code]');

      pageCodes.forEach(link => {
        const linkCode = link.getAttribute('data-code');
        if (linkCode) {
          if (linkCode === curentPageCode) {
            const parentMenu = link.closest('.nav-wrap__menu-item.depth2');
            const hasParentAccordion = link.closest('.nav-wrap__menu-item--ty1');
            const accordion = hasParentAccordion.querySelector('[data-acc-header]');
            if (parentMenu) {
              const containerID = parentMenu.getAttribute('id');
              activeMainDepth(containerID);
            }

            if (accordion) {
              // hash change 문제 발생 시 아래 코드로 대체하여 해결 가능
              accordion.click(); // 클릭 이벤트 발생시켜 아코디언 오픈
              // allMenu.open(accordion); // 아코디언 API 를 통해 아코디언 오픈
            } else {
            }
            link.classList.add('is-active');
          }
        }
      });
    };

    EventHandler.on(headerOpenner, 'click', openMenu);
    EventHandler.on(headerOpenner2, 'click', openMenu);
    EventHandler.on(allMenuCloseButoton, 'click', closeMenu);

    menuDepth.forEach(el => {
      EventHandler.on(el, 'click', e => {
        e.preventDefault();
        const href = e.currentTarget.getAttribute('href');
        const target = document.querySelector(href);
        hide();
        show(target);
        activeMenu(e.currentTarget);
      });
    });
  }
};

