/**
 * scroll move
 */
const gotoScrollY = () => {
  const scTopTrigger = document.querySelectorAll('[data-scroll-top]');
  scTopTrigger.forEach(target => {
    if (initializeCheck(target)) {
      setInitialize(target);
      EventHandler.off('click');
      EventHandler.on(target, 'click', e => {
        const scTargetString = target.getAttribute('data-scroll-top');
        const scTargetStringArr = scTargetString.split('|');
        const scTargetName = scTargetStringArr[0];
        const diffNum = scTargetStringArr[1] || 0;
        const scTarget = document.querySelector(scTargetName);
        if (scTarget) {
          e.preventDefault();
          scrollTo({
            top: scTarget.getBoundingClientRect().top + (window.pageYOffset - parseInt(diffNum)),
            behavior: 'smooth',
          });
        }
      });
    }
  });
};

/**
 * main gnb
 */
const mainGnb = () => {
  const gnbWrap = document.querySelector('.main-gnb');
  if (gnbWrap) {
    if (gnbWrap.classList.contains('main')) return;
    const mainDepthMenu = document.querySelectorAll('.nav-depth--one li');
    const mainDepthContainer = document.querySelector('.nav-depth--one');
    const subDepthMenuLinks = document.querySelectorAll('.nav-depth--two li');
    const threeDepthMenu = document.querySelectorAll('.nav-depth--three');

    const openSubDepth = (target, parent = null) => {
      try {
        const child = document.querySelector(target);
        if (child) {
          const sb = child.parentElement.children;
          [...sb].forEach(el => {
            el.scrollLeft = 0;
            el.classList.remove('is-active');
          });
          child.classList.add('is-active');
        } else {
          if (parent) {
            parent.forEach(el => {
              el.scrollLeft = 0;
              el.classList.remove('is-active');
            });
          }
        }
      } catch (e) {
        parent.forEach(el => {
          el.scrollLeft = 0;
          el.classList.remove('is-active');
        });
      }
    };

    const activeDepth1 = target => {
      mainDepthMenu.forEach(el => {
        el.querySelector('a').classList.remove('is-active');
      });
      target.classList.add('is-active');
    };

    const activeDepth2 = target => {
      subDepthMenuLinks.forEach(el => {
        el.querySelector('a').classList.remove('is-active');
      });
      target.classList.add('is-active');
    };

    EventHandler.on(gnbWrap, 'click', e => {
      const target = e.target;
      const depth1Target = target.closest('.nav-depth1');
      const depth2Target = target.closest('.nav-depth2');
      if (depth1Target) {
        const me = depth1Target.querySelector('a');
        if (me.getAttribute('href').indexOf('#') > -1) {
          e.preventDefault();
        }
        // 메뉴 활성화 시키고 하위메뉴 노출
        activeDepth1(me);
        openSubDepth(me.getAttribute('href'));
        openSubDepth(null, threeDepthMenu);
      } else if (depth2Target) {
        const me = depth2Target.querySelector('a');
        if (me.getAttribute('href').indexOf('#') > -1) {
          e.preventDefault();
          // 메뉴 활성화 시키고 하위메뉴 노출
          activeDepth2(me);
          // 하위메뉴 노출
          openSubDepth(me.getAttribute('href'), threeDepthMenu);
        }
      }
    });

    const active = () => {
      const location = window.location;
      const allLinks = document.querySelectorAll('.main-gnb a');
      const currentPathArr = location.pathname.split('/');
      const currentPathName = currentPathArr[currentPathArr.length - 1];
      allLinks.forEach(link => {
        const linkString = link.getAttribute('href');
        if (linkString.indexOf(currentPathName) > -1) {
          findParent(link);
        }
      });
    };

    const activeParent = el => {
      if (el) {
        const rootID = el.getAttribute('id');
        const rootEl = document.querySelector(`[href="#${rootID}"]`);
        if (rootEl) {
          scrollX(rootEl, mainDepthContainer);
          rootEl.classList.add('is-active');
        }
        el.classList.add('is-active');
      }
    };

    const scrollX = (el, container) => {
      const myRect = el.getBoundingClientRect();
      const diff = myRect.left + myRect.width - gnbWrap.offsetWidth;
      if (diff > 0) {
        container.scrollTo({
          left: diff + 10,
          behavior: 'smooth',
        });
      }
    };

    const findParent = link => {
      const depth3 = link.closest('.nav-depth--three');
      const depth2 = link.closest('.nav-depth--two');
      const depth1 = link.closest('.nav-depth--one');
      // 현재 페이지가 3뎁스 링크에 해당하는 페이지
      if (depth3) {
        // 나에게 직접(3뎁스) active 클래스 부여하여 active 상태 처리
        link.classList.add('is-active');
        // 나의 상위 부모를 찾아서 부모에게도 active 처리
        const parentId = depth3.getAttribute('id');
        const parentEl = document.querySelector(`#${parentId}`);
        parentEl.classList.add('is-active');
        const twoDepthContainer = document.querySelector('.nav-container-two');
        const twoDepthEl = twoDepthContainer.querySelector(`[href="#${parentId}"]`);
        const twoDepthParent = twoDepthEl.closest('.nav-depth--two');
        if (twoDepthEl) twoDepthEl.classList.add('is-active');
        // 상위 메뉴를 찾아 활성화 시킨다.
        activeParent(twoDepthParent);

        scrollX(twoDepthEl, twoDepthParent);
        // 3뎁스 메뉴 스크롤
        scrollX(link, parentEl);
      } else if (depth2) {
        // 현재 페이지가 2뎁스 링크에 해당하는 페이지
        link.classList.add('is-active');
        const twoDepthParent = link.closest('.nav-depth--two');
        // 상위 메뉴를 찾아 활성화 시킨다.
        activeParent(twoDepthParent);
        scrollX(link, twoDepthParent);
      } else if (depth1) {
        //
      }
    };

    active();
  }
};

/**
 * 메인 faq 아이콘
 */
const fabAction = () => {
  const fab = document.querySelector('.c-fab');
  const fabOpen = document.querySelector('.c-fab__open');
  const fabDim = document.querySelector('.fab-dim');
  let checkTime = null;
  if (!!fab) {
    EventHandler.on(fabDim, 'touchstart', e => {
      e.preventDefault();
    });
    actions.add('fabAction', () => {
      if (checkTime) {
        clearTimeout(checkTime);
        checkTime = null;
      }
      if (fab.classList.contains('is-active')) {
        fab.style.display = '';
        fab.classList.remove('is-active');
      }

      checkTime = setTimeout(() => {
        if (!fab.classList.contains('is-active')) {
          fab.style.display = 'block';
          // eslint-disable-next-line no-unused-vars
          const reflow = fab.offsetHeight;
          fab.classList.add('is-active');
        }
      }, 300);
    });

    fabOpen.addEventListener('click', () => {
      fabOpen.checked ? (fabDim.style.display = 'block') : (fabDim.style.display = 'none');
    });
  }
};

/**
 * 아코디언 열렸을 때 상위 배너 아웃라인 삭제
 * @param {*} accordion
 */
const accordState = accordion => {
  const accEl = document.querySelector('.with-expand-flag');
  if (!!accEl) {
    const expandFlag = document.querySelector('.expand-flag');
    // 열릴 때
    accEl.addEventListener(KTM.Accordion.EVENT.OPEN, () => {
      expandFlag.classList.add('is-expanded');
    });
    // 닫힐 때
    accEl.addEventListener(KTM.Accordion.EVENT.CLOSE, () => {
      expandFlag.classList.remove('is-expanded');
    });
  }
};

const floatingBottomSheetAction = () => {
  const bottomSheet = document.querySelector('.c-button-wrap--b-floating');
  if (bottomSheet) {
    actions.add('floatingBottomSheetAction', () => {
      const scTop = window.scrollTop || window.pageYOffset;
      if (scTop > 150) {
        // 한번만 등장하면 해당 루틴은 종료되니 등장시키고 등록 된 스크롤 핸들러 삭제
        bottomSheet.classList.add('is-active');
        actions.remove('floatingBottomSheetAction');
      }
    });
  }
};

const activePosForTabHeader = el => {
  const activeElement = typeof el === 'string' ? document.querySelector(el) : el;
  if (!activeElement) return;
  const viewport = activeElement.parentNode;
  // 스크롤 영역이 있어야 실행한다.
  if (viewport.offsetWidth < viewport.scrollWidth - 40) {
    const activeElementRect = activeElement.getBoundingClientRect();
    viewport.scrollTo({
      // 죠금 여유롭게 10px
      left: activeElementRect.left + viewport.scrollLeft - 40,
      behavior: 'smooth',
    });
  }
};

const tabHeaderAutoScroller = () => {
  const tabScrollHeaders = document.querySelectorAll('[data-active-scroll]');
  if (tabScrollHeaders.length > 0) {
    tabScrollHeaders.forEach(header => {
      if (initializeCheck(header)) {
        setInitialize(header);
        if (header.classList.contains('is-active')) {
          activePosForTabHeader(header);
        }
        EventHandler.on(header, 'click.scroll-header', event => {
          activePosForTabHeader(header);
        });
      }
    });
  }
};

const fakeDateInput = () => {
  const dateInputs = document.querySelectorAll('.date-input');
  if (dateInputs.length > 0) {
    dateInputs.forEach(el => {
      if (initializeCheck(el)) {
        setInitialize(el);
        const wrap = el.closest('.c-form__input');
        const fakeInput = document.createElement('input');
        fakeInput.type = 'date';
        fakeInput.className = 'c-hidden';
        el.parentNode.insertBefore(fakeInput, el.nextSibling);
        EventHandler.off(fakeInput, 'change.fake');
        EventHandler.on(fakeInput, 'change.fake', e => {
          el.value = fakeInput.value;
          if (wrap) {
            if (el.value.length > 0) {
              wrap.classList.add('has-value');
            } else {
              if (wrap.classList.contains('has-value')) {
                wrap.classList.remove('has-value');
              }
            }
          }
          EventHandler.trigger(el, 'change');
        });

        EventHandler.off(el, 'click.fake');
        EventHandler.on(el, 'click.fake', e => {
          e.preventDefault();
          fakeInput.focus();
          fakeInput.click();
        });
      }
    });
  }
};

const tabChangeToScroll = () => {
  const elements = document.querySelectorAll('[data-changed-scroll]');
  elements.forEach(el => {
    if (initializeCheck(el)) {
      setInitialize(el);
      EventHandler.on(el, 'ui.tab.change', event => {
        let diffSpacing = 0;
        const header = document.querySelector('.ly-page-sticky');
        if (header) {
          diffSpacing += header.offsetHeight;
        }
        const tablist = event.current.header.closest('[role="tablist"]');
        if (tablist) {
          diffSpacing += tablist.offsetHeight;
        }
        const currentContentRect = event.current.content.getBoundingClientRect();
        const resultY = currentContentRect.top + window.pageYOffset - diffSpacing;

        if (diffSpacing < window.pageYOffset) {
          window.scrollTo({
            top: resultY,
          });
        }
      });
    }
  });
};

